// Parse LLM response
const raw = $json.output?.[0]?.content?.[0]?.text ?? '';
let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e) {
  return [{ json: { error: 'LLM parse failed', raw: raw.slice(0, 200) } }];
}

// Build set of valid supplier names
const validSuppliers = new Set(
  (parsed.groups ?? [])
    .filter(g => g.is_valid === true)
    .map(g => g.group_name)
);

// Filter all files from Extract ZIP to only valid suppliers
const allFiles = $items('Extract ZIP');
const output = [];

for (const item of allFiles) {
  const binaries = item.binary || {};
  for (const file of Object.values(binaries)) {
    const dir = (file.directory || '').split('/')[0];
    const supplier = dir.replace(/\s*\d{4,}.*$/, '').trim();
    if (!validSuppliers.has(supplier)) continue;

    const taggedFile = { ...file, supplierTag: supplier };
    const name = (file.fileName || '').toLowerCase();
    let type = 'unknown';
    if (name.match(/\.(jpg|jpeg|png|webp)$/)) type = 'image';
    else if (name.endsWith('.pdf')) type = 'pdf';
    else if (name.match(/\.(xlsx|xls|sheet)$/)) type = 'excel';
    else if (name.endsWith('.txt')) type = 'text';

    output.push({
      json: { supplier, type },
      binary: { data: taggedFile }
    });
  }
}

return output;

const llmOutputs = $input.all();
const supplierGroups = $('Group By Supplier').all();
const allFiles = $('Filter Valid Suppliers').all();
const output = [];

for (let i = 0; i < llmOutputs.length; i++) {
  const llmItem = llmOutputs[i];
  const sourceItem = supplierGroups[i];

  let textField = llmItem.json?.output?.[0]?.content?.[0]?.text ?? null;
  let raw = '';
  if (typeof textField === 'string') raw = textField;
  else if (typeof textField === 'object' && textField?.message) raw = textField.message;

  let parsed;
  try { parsed = JSON.parse(raw); } catch { parsed = {}; }

  const supplier = parsed.supplier ?? sourceItem?.json?.supplier ?? null;

  let patterns = [];
  if (Array.isArray(parsed.patterns)) patterns = parsed.patterns;
  else if (parsed.pattern && parsed.pattern !== 'unknown') patterns = [parsed.pattern];

  if (!supplier || patterns.length === 0) continue;
  const patternSet = new Set(patterns);

  for (const fileItem of allFiles) {
    if (fileItem.json?.supplier !== supplier) continue;

    const file = fileItem.binary?.data ?? {};
    const rawFileName = file.fileName ?? '';
    const fileName = rawFileName.toLowerCase();

    let fileType = 'unknown';

    // ── ✅ .txt يُفحص أولاً ──
    if (fileName.endsWith('.txt')) {
      const stripped = fileName.slice(0, -4);

      // MIME artifacts من ملفات بصيغ ثنائية — تجاهل
      if (
        stripped.match(/spreadsheetml/i) ||
        stripped.match(/\.sheet$/i) ||
        stripped.match(/\.pdf$/i) ||
        stripped.match(/\.xlsx?$/i) ||
        stripped.match(/officedocument/i) ||
        stripped.match(/vnd\.ms-excel/i) ||
        stripped.match(/\.(jpe?g|png|webp)$/i)
      ) {
        continue;
      }

      fileType = 'text';

    } else if (fileName.match(/\.(jpg|jpeg|png|webp)$/)) {
      fileType = 'image';

    } else if (fileName.endsWith('.pdf')) {
      fileType = 'pdf';

    } else if (
      fileName.match(/\.(xlsx|xls)$/) ||
      fileName.match(/spreadsheetml\.sheet$/) ||
      fileName.match(/officedocument\.spreadsheetml/) ||
      fileName.match(/vnd\.ms-excel/)
    ) {
      fileType = 'excel';
    }

    if (fileType === 'unknown') continue;
    if (!patternSet.has(fileType)) continue;

    output.push({
      json: {
        supplier,
        pattern: fileType,
        type: fileType,
        fileName: rawFileName
      },
      binary: { data: file }
    });
  }
}

return output;

