const extractItems = $('Extract Excel').all();
const sourceFiles = $('Prepare Excel Item').all();

const NAME_KEYWORDS  = ['اسم الصنف', 'إسم الصنف', 'اسم المنتج', 'المنتج', 'الصنف', 'name', 'product'];
const PRICE_KEYWORDS = ['سعر البيع', 'سعر الاول', 'السعر', 'سعر', 'price', 'cost'];
const UNIT_KEYWORDS  = ['وحدة', 'الوحدة', 'العبوة', 'unit', 'pack'];
const SKIP_KEYWORDS  = ['رقم', 'الرقم', 'كود', 'no.', 'id'];
const GENERIC_UNITS  = ['box', 'carton', 'pack'];

function normalize(v) { return (v || '').toString().trim().toLowerCase(); }
function matchesKeyword(val, keywords) {
  const n = normalize(val);
  return keywords.some(k => n.includes(normalize(k)));
}

// ── جمّع rows حسب الملف باستخدام pairedItem ──
const fileGroups = {};

for (const item of extractItems) {
  const fileIdx = item.pairedItem?.item ?? 0;
  if (!fileGroups[fileIdx]) fileGroups[fileIdx] = [];
  fileGroups[fileIdx].push(item.json);
}

const output = [];

// ── عالج كل ملف لحاله ──
for (const [fileIdxStr, allRows] of Object.entries(fileGroups)) {
  const fileIdx = parseInt(fileIdxStr, 10);
  const supplier = sourceFiles[fileIdx]?.json?.supplier ?? null;

  let nameKey = null, priceKey = null, unitKey = null;
  let startIndex = 0;

  // Detect from keys
  const firstRow = allRows[0] ?? {};
  for (const key of Object.keys(firstRow)) {
    if (SKIP_KEYWORDS.some(sk => normalize(key).includes(normalize(sk)))) continue;
    if (!nameKey  && matchesKeyword(key, NAME_KEYWORDS))  nameKey  = key;
    if (!priceKey && matchesKeyword(key, PRICE_KEYWORDS)) priceKey = key;
    if (!unitKey  && matchesKeyword(key, UNIT_KEYWORDS))  unitKey  = key;
  }

  // Fallback: scan values
  if (!nameKey || !priceKey) {
    for (let i = 0; i < Math.min(5, allRows.length); i++) {
      const row = allRows[i];
      for (const [key, val] of Object.entries(row)) {
        if (SKIP_KEYWORDS.some(sk => normalize(key).includes(normalize(sk)))) continue;
        if (!nameKey  && matchesKeyword(val, NAME_KEYWORDS))  nameKey  = key;
        if (!priceKey && matchesKeyword(val, PRICE_KEYWORDS)) priceKey = key;
        if (!unitKey  && matchesKeyword(val, UNIT_KEYWORDS))  unitKey  = key;
      }
      if (nameKey && priceKey) {
        startIndex = i + 1;
        break;
      }
    }
  }

  // Smart fallback
  if (!nameKey || !priceKey) {
    const sample = allRows.slice(0, 20);
    const keys = Object.keys(sample[0] || {}).filter(k =>
      !SKIP_KEYWORDS.some(sk => normalize(k).includes(normalize(sk)))
    );
    for (const key of keys) {
      let textCount = 0, smallNumCount = 0;
      for (const row of sample) {
        const val = row[key];
        if (typeof val === 'string' && val.trim().length > 3) textCount++;
        const num = parseFloat(val);
        if (!isNaN(num) && num > 0 && num < 5000) smallNumCount++;
      }
      const total = sample.length;
      if (!nameKey && textCount >= total * 0.5) nameKey = key;
      if (!priceKey && smallNumCount >= total * 0.5 && key !== nameKey) priceKey = key;
    }
  }

  if (!nameKey || !priceKey) continue;

  // Extract products
  for (let i = startIndex; i < allRows.length; i++) {
    const row = allRows[i];
    const rawName  = row[nameKey];
    const rawPrice = row[priceKey];
    const rawUnit  = unitKey ? row[unitKey] : null;

    if (!rawName || typeof rawName !== 'string') continue;

    let name = rawName.trim();

    if (rawUnit && typeof rawUnit === 'string') {
      const u = rawUnit.trim();
      if (u.length > 0 && !GENERIC_UNITS.includes(u.toLowerCase())) {
        name = `${name} ${u}`;
      }
    }

    const price = rawPrice !== null && rawPrice !== undefined
      ? (typeof rawPrice === 'number' ? rawPrice : parseFloat(rawPrice) || null)
      : null;

    if (name.length < 2) continue;
    if (/^\d+$/.test(name.trim())) continue;
    if (matchesKeyword(name, NAME_KEYWORDS) || matchesKeyword(name, PRICE_KEYWORDS)) continue;
    if (price === 0) continue;

    output.push({ json: { name: name.trim(), price, supplier, source: 'excel' } });
  }
}

return output;

const BATCH_SIZE = 100;
const output = [];
const flat = [];

for (const item of $input.all()) {
  // If item came from image branch — unwrap products array
  if (Array.isArray(item.json?.products)) {
    for (const p of item.json.products) {
      flat.push(p);
    }
  } else {
    // PDF and Excel items arrive already flat
    flat.push(item.json);
  }
}

for (let i = 0; i < flat.length; i += BATCH_SIZE) {
  output.push({
    json: { items: flat.slice(i, i + BATCH_SIZE) }
  });
}

return output;

function makeGroupKey(norm) {
  if (!norm) return null;
  return norm
    .replace(/[^\w\s\u0600-\u06ff\u00C0-\u024F%./]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .substring(0, 100);
}

// function isInvalid(val) {
//   return !val || val.trim().toUpperCase() === 'INVALID';
// }

const llmOutputs = $input.all();
const batchInputs = $('Batch for Normalization').all();
const output = [];

for (let b = 0; b < llmOutputs.length; b++) {
  const rawText = llmOutputs[b].json?.output?.[0]?.content?.[0]?.text ?? null;
  const originals = batchInputs[b]?.json?.items ?? [];

  let parsed = null;
  if (rawText) {
    try {
      const clean = rawText
        .replace(/^```json\s*/i, '')
        .replace(/```\s*$/i, '')
        .trim();
      parsed = JSON.parse(clean);
      if (!Array.isArray(parsed)) parsed = [parsed];
    } catch(e) { parsed = null; }
  }

  for (let i = 0; i < originals.length; i++) {
    const orig = originals[i];
    const llm = parsed?.[i] ?? null;

    // Drop items the AI flagged as invalid
    //if (llm && isInvalid(llm.name)) continue;

    const llmName = llm?.name?.trim() ?? null;
  const isInvalidFlag = llmName?.toUpperCase() === 'INVALID';

  // If LLM flagged INVALID, use original name instead of dropping
  const finalName = (!llmName || isInvalidFlag)
    ? (orig.name ?? null)
    : llmName;
    // const finalName = llm?.name?.trim() ?? orig.name ?? null;
    // if (!finalName) continue;

  const llmNorm = llm?.name_normalized?.trim() ?? null;
  const isInvalidNorm = llmNorm?.toUpperCase() === 'INVALID';

  const finalNorm = (
    llmNorm &&
    !isInvalidNorm &&
    llmNorm === llmNorm.toLowerCase() &&
    llmNorm.length >= 2
  )
    ? llmNorm
    : orig.name?.toLowerCase().trim() ?? null;

    if (!finalNorm) continue;

    // Price always from original — never trust LLM with price
    const price = typeof orig.price === 'number'
      ? orig.price
      : (parseFloat(orig.price) || null);

    output.push({
      json: {
        name: finalName,
        name_normalized: finalNorm,
        _group_key: makeGroupKey(finalNorm),
        price,
        supplier: orig.supplier ?? null,
        source: orig.source ?? null
      }
    });
  }
}

return output;

const BATCH_SIZE = 150;
const all = $input.all().map(i => i.json);
const batches = [];

for (let i = 0; i < all.length; i += BATCH_SIZE) {
  batches.push({
    json: { items: all.slice(i, i + BATCH_SIZE) }
  });
}

return batches;

const LINES_PER_CHUNK = 50;
const output = [];

// Build a fileName → supplier lookup from Filter Valid Suppliers
const supplierLookup = {};
for (const item of $('Filter Valid Suppliers').all()) {
  const file = item.binary?.data ?? {};
  const fileName = file.fileName ?? '';
  const supplier = file.supplierTag ?? item.json?.supplier ?? null;
  if (fileName && supplier) {
    supplierLookup[fileName] = supplier;
  }
}

for (const item of $input.all()) {
  const text = item.json?.text ?? '';

  // Try binary tag first
  let supplier = (item.binary?.data || {}).supplierTag ?? null;

  // Fallback: match by fileName against Filter Valid Suppliers lookup
  if (!supplier) {
    const fileName = item.binary?.data?.fileName ?? '';
    supplier = supplierLookup[fileName] ?? null;
  }

  if (!text) continue;

  const lines = text
    .split('\n')
    .map(l => l.trim())
    .filter(Boolean);

  const totalChunks = Math.ceil(lines.length / LINES_PER_CHUNK);

  for (let i = 0; i < lines.length; i += LINES_PER_CHUNK) {
    const chunkLines = lines.slice(i, i + LINES_PER_CHUNK);
    output.push({
      json: {
        text: chunkLines.join('\n'),
        supplier,
        chunk_index: Math.floor(i / LINES_PER_CHUNK),
        total_chunks: totalChunks
      }
    });
  }
}

return output;

const output = [];

for (const item of $input.all()) {
  if (item.json._skip) continue;

  const products = item.json.products ?? [];
  for (const p of products) {
    output.push({ json: p });
  }
}

return output;

const rawText =
  $json.output?.[0]?.content?.[0]?.text ??
  $json.content?.[0]?.text ??
  null;

if (!rawText) return { json: { _skip: true } };

let parsed;
try {
  const clean = rawText
    .replace(/^```json\s*/i, '')
    .replace(/```\s*$/i, '')
    .trim();
  parsed = JSON.parse(clean);
  if (!Array.isArray(parsed)) parsed = [parsed];
} catch(e) {
  return { json: { _skip: true } };
}

return {
  json: {
    groups: parsed.filter(g => g?.name)
  }
};

const finalGroups = {};

for (const item of $input.all()) {
  if (item.json._skip) continue;

  const groups = item.json.groups ?? [];

  for (const group of groups) {
    const key = (group.name_normalized ?? group.name ?? '')
      .toLowerCase()
      .replace(/[^\w\s\u0600-\u06ff\u00C0-\u024F%./]/g, ' ')
      .replace(/\s+/g, ' ')
      .trim()
      .substring(0, 100);

    if (!key) continue;

    if (!finalGroups[key]) {
      finalGroups[key] = {
        name: group.name,
        name_normalized: group.name_normalized ?? key,
        best_price: null,
        best_supplier: null,
        offers_count: 0,
        all_offers: []
      };
    }

    const existing = finalGroups[key];

    if (group.name && group.name.length > (existing.name?.length ?? 0)) {
      existing.name = group.name;
    }

    for (const offer of (group.all_offers ?? [])) {
      if (offer.price === null || offer.price === undefined) continue;

      const isDuplicate = existing.all_offers.find(
        o => o.supplier === offer.supplier && o.price === offer.price
      );

      if (!isDuplicate) {
        existing.all_offers.push(offer);

        if (existing.best_price === null || offer.price < existing.best_price) {
          existing.best_price = offer.price;
          existing.best_supplier = offer.supplier;
        }
      }
    }
  }
}

return Object.values(finalGroups)
  .map(g => {
    g.all_offers.sort((a, b) => a.price - b.price);
    g.offers_count = g.all_offers.length;
    return { json: g };
  })
  .sort((a, b) => (a.json.name ?? '').localeCompare(b.json.name ?? ''));

