const sourceFiles = $('Filter Valid Suppliers').all();
const output = [];

function findSupplier(fileName) {
  const fileItem = sourceFiles.find(f =>
    (f.binary?.data?.fileName ?? '') === fileName
  );
  return fileItem?.json?.supplier ?? null;
}

for (const item of $input.all()) {
  const fileName = item.binary?.data?.fileName ?? '';
  const supplier = findSupplier(fileName);

  // الـ text موجود في item.json.data أو item.json.text حسب Extract from File
  const text = item.json?.data ?? item.json?.text ?? '';
  if (!text || typeof text !== 'string') continue;

  // كل سطر = منتج واحد، السعر آخر رقم في السطر
  const lines = text.split(/\r?\n/).map(l => l.trim()).filter(Boolean);

  for (const line of lines) {
    const match = line.match(/(\d+(?:\.\d+)?)\s*$/);
    if (!match) continue;

    const price = parseFloat(match[1]);
    const name = line.replace(/(\d+(?:\.\d+)?)\s*$/, '').trim();

    if (!name || name.length < 2) continue;
    if (price === 0) continue;

    output.push({
      json: {
        name,
        price,
        supplier,
        source: 'text'
      }
    });
  }
}

return output;

const groups = {};

for (const item of $input.all()) {
  const supplier = item.json?.supplier ?? null;
  if (!supplier) continue;

  if (!groups[supplier]) {
    groups[supplier] = {
      supplier,
      files: [],
      decoded_files: [],
      txt_contents: []
    };
  }

  const file = item.binary?.data ?? {};
  const rawFileName = file.fileName ?? '';
  const fileName = rawFileName.toLowerCase();

  groups[supplier].files.push(rawFileName);

  // Decode MIME-type .txt filenames to reveal original type
  if (fileName.endsWith('.txt')) {
    const stripped = fileName.slice(0, -4);
    let interpretation = 'text file';
    if (stripped.match(/\.(xlsx|xls)$/i) || stripped.match(/sheet|spreadsheet|officedocument\.spreadsheetml/i))
      interpretation = 'Excel file (extracted text)';
    else if (stripped.match(/\.pdf$/i) || stripped.match(/pdf/i))
      interpretation = 'PDF file (extracted text)';
    groups[supplier].decoded_files.push(`${rawFileName} → [${interpretation}]`);

    // Read txt content
    try {
      const buffer = Buffer.from(file.data, 'base64');
      const text = buffer.toString('utf8').trim();
      if (text) {
        groups[supplier].txt_contents.push({
          file: rawFileName,
          content: text.substring(0, 500)
        });
      }
    } catch(e) {}
  } else {
    groups[supplier].decoded_files.push(rawFileName);
  }
}

return Object.values(groups).map(g => ({ json: g }));

